import './BadgeContent.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Typography } from '../../Typography';
import { formatNumber } from '../utils';
import type { BadgeContentProps } from './BadgeContent.types';

export const BadgeContent: FC<BadgeContentProps> = ({
	count,
	error = false,
	warning = false,
	hideBadgeContent = false,
	size = 'small',
	stanalone,
}) => {
	const badgeContent = useMemo(() => formatNumber(count), [count]);

	return (
		<Typography
			data-testid="BadgeContent"
			className={classNames('dsb_badge', `dsb_badge--${size}`, {
				'dsb_badge--error': error,
				'dsb_badge--exclamation': warning,
				'dsb_badge--standalone': stanalone,
			})}
			variant="overline"
		>
			{!hideBadgeContent && (warning ? '!' : badgeContent)}
		</Typography>
	);
};
